│   ├── setup-surface.ts        # Setup wizard (interactive onboarding)
│   ├── monitor.ts              # Gateway: listening/polling loop
│   ├── inbound.ts              # Message parsing/normalization
│   ├── send.ts                 # Outbound message sending
