import type { OpenClawConfig, PluginRuntime } from "../runtime-api.js";

/** DM access-control policy for a PulseBoard account. */
export type PulseBoardDmPolicy = "pairing" | "allowlist" | "open" | "disabled";

/**
 * Raw config shape read from channels.pulseboard.* in openclaw.yml.
 * All fields are optional because config may be partially provided via
 * environment variables.
 */
export interface PulseBoardAccountConfig {
  /** Human-readable display name for this connection. */
  name?: string;
  /** Whether this channel is enabled. Defaults to true. */
  enabled?: boolean;
  /**
   * Base URL of the PulseBoard server.
   * Example: https://pb.example.com
   * Env var: PULSEBOARD_HOST (default account only).
   */
  host?: string;
  /**
   * API key (personal access token) for authenticating to the server.
   * Env var: PULSEBOARD_API_KEY (default account only).
   */
  apiKey?: string;
  /**
   * The bot's username on the PulseBoard server.
   * Env var: PULSEBOARD_USERNAME (default account only).
   */
  username?: string;
  /**
   * Board names to join and monitor for incoming posts.
   * Example: ["general", "tech", "announcements"]
   */
  boards?: string[];
  /** DM access policy. Defaults to "pairing". */
  dmPolicy?: PulseBoardDmPolicy;
  /**
   * Allowed sender usernames for DMs.
   * Use "*" to allow all senders when dmPolicy is "open" or "allowlist".
   */
  allowFrom?: Array<string | number>;
  /** Markdown table rendering mode. */
  markdown?: {
    tables?: "plain" | "md" | "ascii";
  };
}

/** Top-level channels.pulseboard config block (single-account). */
export interface PulseBoardConfig extends PulseBoardAccountConfig {
  /** Override which account is used as the default. */
  defaultAccount?: string;
}

/** OpenClawConfig extended with the pulseboard channel section. */
export type CoreConfig = OpenClawConfig & {
  channels?: OpenClawConfig["channels"] & {
    pulseboard?: PulseBoardConfig;
  };
};

export type { PluginRuntime };

/** A single message received from the PulseBoard server. */
export interface PulseBoardInboundMessage {
  /** Unique message ID assigned by the server. */
  messageId: string;
  /**
   * Normalized target of the conversation:
   *   #boardname  – a board (group) message
   *   @username   – a direct message
   */
  target: string;
  /** Username of the message sender. */
  senderUsername: string;
  /** Raw text body of the message. */
  text: string;
  /** Unix timestamp in milliseconds. */
  timestamp: number;
  /** True when the message was posted to a board; false for a DM. */
  isGroup: boolean;
}

