import {
  AllowFromListSchema,
  buildChannelConfigSchema,
  DmPolicySchema,
  MarkdownConfigSchema,
} from "openclaw/plugin-sdk/channel-config-primitives";
import { buildSecretInputSchema } from "openclaw/plugin-sdk/secret-input";
import { z } from "openclaw/plugin-sdk/zod";

/**
 * Zod schema for channels.pulseboard.* configuration.
 *
 * All fields are optional at the schema level; required fields are
 * validated at runtime via resolvePulseBoardAccount.
 */
export const PulseBoardConfigSchema = z.object({
  /** Human-readable display name for this connection. */
  name: z.string().optional(),

  /** Whether this channel is enabled. Defaults to true. */
  enabled: z.boolean().optional(),

  /**
   * Base URL of the PulseBoard server.
   * Must be an http:// or https:// URL.
   * Example: https://pb.example.com
   */
  host: z
    .string()
    .url()
    .refine(
      (url) => {
        try {
          const { protocol } = new URL(url);
          return protocol === "https:" || protocol === "http:";
        } catch {
          return false;
        }
      },
      { message: "Host must be an http:// or https:// URL." },
    )
    .optional(),

  /**
   * API key (personal access token) used to authenticate requests.
   * Supports plain strings or SecretRef file references.
   */
  apiKey: buildSecretInputSchema().optional(),

  /** The bot's username on the PulseBoard server. */
  username: z.string().min(1).max(64).optional(),

  /**
   * Board names to join and monitor for incoming messages.
   * Board names must be 1–64 characters: letters, digits, hyphens, underscores.
   */
  boards: z.array(z.string().min(1).max(64)).optional(),

  /** DM access policy: pairing, allowlist, open, or disabled. Defaults to pairing. */
  dmPolicy: DmPolicySchema.optional(),

  /**
   * Allowed sender usernames for DMs (bare usernames or "*" for all).
   * Required when dmPolicy is "allowlist" or "open".
   */
  allowFrom: AllowFromListSchema,

  /** Markdown table rendering options. */
  markdown: MarkdownConfigSchema,
});

export type PulseBoardSchemaConfig = z.infer<typeof PulseBoardConfigSchema>;

/** JSON Schema for the Control UI config panel and config validation. */
export const pulseBoardChannelConfigSchema = buildChannelConfigSchema(PulseBoardConfigSchema);

