import { DEFAULT_ACCOUNT_ID, normalizeAccountId } from "openclaw/plugin-sdk/account-id";
import {
  listCombinedAccountIds,
  resolveListedDefaultAccountId,
} from "openclaw/plugin-sdk/account-resolution";
import { normalizeSecretInputString } from "openclaw/plugin-sdk/secret-input";
import type { OpenClawConfig } from "../runtime-api.js";
import type { CoreConfig, PulseBoardAccountConfig, PulseBoardDmPolicy } from "./types.js";

/** A fully resolved PulseBoard account with all env-var overrides applied. */
export interface ResolvedPulseBoardAccount {
  accountId: string;
  name?: string;
  enabled: boolean;
  /**
   * True when host, apiKey, and username are all present and non-empty.
   * The gateway refuses to start an unconfigured account.
   */
  configured: boolean;
  /** Resolved base URL of the PulseBoard server. */
  host: string;
  /** Resolved API key. Never empty when configured is true. */
  apiKey: string;
  /** Resolved bot username. Never empty when configured is true. */
  username: string;
  /** Board names to join and monitor. */
  boards: string[];
  dmPolicy: PulseBoardDmPolicy;
  allowFrom: Array<string | number>;
  /** Raw config section (after env-var merging). */
  config: PulseBoardAccountConfig;
}

/** Extract the raw pulseboard config block from the top-level config. */
function rawPulseBoardConfig(cfg: OpenClawConfig): PulseBoardAccountConfig | undefined {
  return (cfg.channels as Record<string, unknown> | undefined)?.["pulseboard"] as
    | PulseBoardAccountConfig
    | undefined;
}

function resolveConfiguredDefaultAccountId(cfg: OpenClawConfig): string | undefined {
  const raw = rawPulseBoardConfig(cfg);
  // PulseBoardConfig adds defaultAccount on top of PulseBoardAccountConfig.
  const defaultAccount = (raw as Record<string, unknown> | undefined)?.["defaultAccount"];
  if (typeof defaultAccount === "string") {
    return defaultAccount.trim() || undefined;
  }
  return undefined;
}

/** List all known PulseBoard account IDs for the given config. */
export function listPulseBoardAccountIds(cfg: OpenClawConfig): string[] {
  const pb = rawPulseBoardConfig(cfg);
  // PulseBoard uses a single implicit account driven by the presence of an API key.
  const apiKey = normalizeSecretInputString(pb?.apiKey as never);
  return listCombinedAccountIds({
    configuredAccountIds: [],
    implicitAccountId: apiKey
      ? (resolveConfiguredDefaultAccountId(cfg) ?? DEFAULT_ACCOUNT_ID)
      : undefined,
  });
}

/** Return the effective default account ID for PulseBoard. */
export function resolveDefaultPulseBoardAccountId(cfg: OpenClawConfig): string {
  return resolveListedDefaultAccountId({
    accountIds: listPulseBoardAccountIds(cfg),
    configuredDefaultAccountId: resolveConfiguredDefaultAccountId(cfg),
  });
}

/**
 * Resolve a PulseBoard account from config, applying env-var overrides for
 * the default account.
 */
export function resolvePulseBoardAccount(opts: {
  cfg: CoreConfig;
  accountId?: string | null;
}): ResolvedPulseBoardAccount {
  const accountId = normalizeAccountId(
    opts.accountId ?? resolveDefaultPulseBoardAccountId(opts.cfg),
  );
  const pb = rawPulseBoardConfig(opts.cfg);
  const isDefault = accountId === DEFAULT_ACCOUNT_ID;

  const enabled = pb?.enabled !== false;

  // Resolve host: config → env var (default account only).
  const host = (
    pb?.host?.trim() ||
    (isDefault ? (process.env["PULSEBOARD_HOST"]?.trim() ?? "") : "") ||
    ""
  ).trim();

  // Resolve API key: config SecretRef → env var (default account only).
  const apiKey =
    normalizeSecretInputString(pb?.apiKey as never) ||
    (isDefault ? (process.env["PULSEBOARD_API_KEY"]?.trim() ?? "") : "") ||
    "";

  // Resolve username: config → env var (default account only).
  const username = (
    pb?.username?.trim() ||
    (isDefault ? (process.env["PULSEBOARD_USERNAME"]?.trim() ?? "") : "") ||
    ""
  ).trim();

  const boards = pb?.boards ?? [];
  const configured = Boolean(host && apiKey && username);

  const config: PulseBoardAccountConfig = {
    name: pb?.name,
    enabled: pb?.enabled,
    host: pb?.host,
    apiKey: pb?.apiKey,
    username: pb?.username,
    boards: pb?.boards,
    dmPolicy: pb?.dmPolicy,
    allowFrom: pb?.allowFrom,
    markdown: pb?.markdown,
  };

  return {
    accountId,
    name: pb?.name?.trim() || undefined,
    enabled,
    configured,
    host,
    apiKey,
    username,
    boards,
    dmPolicy: pb?.dmPolicy ?? "pairing",
    allowFrom: pb?.allowFrom ?? [],
    config,
  };
}

