/** Maximum identifier length for board names and usernames. */
const MAX_IDENT_LEN = 64;

/**
 * Board names: lowercase letters, digits, hyphens, and underscores.
 * Length 1–64.
 */
const BOARD_NAME_RE = /^[a-z0-9_-]{1,64}$/u;

/**
 * Usernames: lowercase letters, digits, hyphens, underscores, dots, and plus signs.
 * Length 1–64.
 */
const USERNAME_RE = /^[a-z0-9_.+-]{1,64}$/u;

/**
 * Normalize a raw board name.
 * Strips one or more leading "#" characters and lowercases the result.
 * Returns null for names that fail validation.
 */
export function normalizeBoardName(raw: string): string | null {
  const stripped = raw.trim().replace(/^#+/, "");
  if (!stripped || stripped.length > MAX_IDENT_LEN) {
    return null;
  }
  const lowered = stripped.toLowerCase();
  return BOARD_NAME_RE.test(lowered) ? lowered : null;
}

/**
 * Normalize a raw DM username.
 * Strips one or more leading "@" characters and lowercases the result.
 * Returns null for names that fail validation.
 */
export function normalizeUsername(raw: string): string | null {
  const stripped = raw.trim().replace(/^@+/, "");
  if (!stripped || stripped.length > MAX_IDENT_LEN) {
    return null;
  }
  const lowered = stripped.toLowerCase();
  return USERNAME_RE.test(lowered) ? lowered : null;
}

/**
 * Normalize a PulseBoard messaging target into canonical form.
 *
 * Canonical forms:
 *   `#boardname`  – post to a named board (group conversation)
 *   `@username`   – send a direct message
 *
 * Accepted input formats:
 *   `#general`            → `#general`
 *   `##General`           → `#general`    (extra # stripped, lowercased)
 *   `@alice`              → `@alice`
 *   `@@Alice`             → `@alice`      (extra @ stripped, lowercased)
 *   `general`             → `#general`    (bare word treated as board name)
 *   `pulseboard:#tech`    → `#tech`       (scheme prefix stripped)
 *   `pulseboard:@bob`     → `@bob`        (scheme prefix stripped)
 *
 * Returns null if the target cannot be normalized.
 */
export function normalizePulseBoardTarget(raw: string): string | null {
  const trimmed = raw.trim();
  if (!trimmed) {
    return null;
  }

  // Strip the optional "pulseboard:" scheme prefix.
  const stripped = trimmed.replace(/^pulseboard:/iu, "");

  if (stripped.startsWith("#")) {
    const board = normalizeBoardName(stripped);
    return board ? `#${board}` : null;
  }

  if (stripped.startsWith("@")) {
    const user = normalizeUsername(stripped);
    return user ? `@${user}` : null;
  }

  // Bare word: treat as a board name (most common intent for bulletin boards).
  const asBoard = normalizeBoardName(stripped);
  if (asBoard) {
    return `#${asBoard}`;
  }

  return null;
}

/** Returns true when the normalized target refers to a board (group). */
export function isBoardTarget(target: string): boolean {
  return target.startsWith("#");
}

/** Returns true when the normalized target refers to a direct message. */
export function isDmTarget(target: string): boolean {
  return target.startsWith("@");
}

/**
 * Quick heuristic used by the messaging targetResolver to decide whether
 * user input looks like a PulseBoard target before full normalization.
 */
export function looksLikePulseBoardTargetId(input: string): boolean {
  const stripped = input.trim().replace(/^pulseboard:/iu, "");
  if (!stripped) {
    return false;
  }
  return stripped.startsWith("#") || stripped.startsWith("@");
}

/**
 * Normalize a single allow-list entry.
 * Entries are bare usernames (no "@") or the wildcard "*".
 * Returns null for entries that cannot be normalized.
 */
export function normalizePulseBoardAllowEntry(raw: string): string | null {
  const trimmed = raw.trim().toLowerCase();
  if (!trimmed) {
    return null;
  }
  if (trimmed === "*") {
    return "*";
  }
  // Allow-list entries are stored as bare usernames (strip any "@" prefix).
  return normalizeUsername(trimmed.replace(/^@/, ""));
}

/**
 * Check whether a sender username is permitted by an allow-list.
 * Used in the inbound DM access resolver.
 */
export function isPulseBoardSenderAllowed(
  senderUsername: string,
  allowFrom: Array<string | number>,
): boolean {
  const normalized = normalizeUsername(senderUsername);
  if (!normalized) {
    return false;
  }
  for (const entry of allowFrom) {
    const ne = normalizePulseBoardAllowEntry(String(entry));
    if (ne === "*" || ne === normalized) {
      return true;
    }
  }
  return false;
}

