import { resolvePulseBoardAccount } from "./accounts.js";
import { isBoardTarget, normalizePulseBoardTarget } from "./normalize.js";
import { getPulseBoardRuntime } from "./runtime.js";
import type { CoreConfig } from "./types.js";

export interface SendPulseBoardResult {
  messageId: string;
  target: string;
}

function recordOutboundActivity(accountId: string): void {
  try {
    getPulseBoardRuntime().channel.activity.record({
      channel: "pulseboard",
      accountId,
      direction: "outbound",
    });
  } catch (err) {
    // Swallow "runtime not initialized" during setup flows; re-throw others.
    if (!(err instanceof Error) || !err.message.includes("PulseBoard runtime not initialized")) {
      throw err;
    }
  }
}

/**
 * Send a text message to a PulseBoard board or direct-message recipient
 * via the PulseBoard REST API.
 *
 * Target format:
 *   `#boardname` – post to a named board
 *   `@username`  – send a direct message
 */
export async function sendMessagePulseBoard(
  to: string,
  text: string,
  opts: { cfg?: CoreConfig; accountId?: string } = {},
): Promise<SendPulseBoardResult> {
  const runtime = getPulseBoardRuntime();
  const cfg = (opts.cfg ?? runtime.config.loadConfig()) as CoreConfig;
  const account = resolvePulseBoardAccount({ cfg, accountId: opts.accountId });

  if (!account.configured) {
    throw new Error(
      `PulseBoard is not configured for account "${account.accountId}". ` +
        "Set channels.pulseboard.host, channels.pulseboard.apiKey, and channels.pulseboard.username.",
    );
  }

  const target = normalizePulseBoardTarget(to);
  if (!target) {
    throw new Error(
      `Invalid PulseBoard target: "${to}". Use #boardname for boards or @username for DMs.`,
    );
  }

  if (!text.trim()) {
    throw new Error("Message must be non-empty for PulseBoard sends.");
  }

  // Map the target to the appropriate REST endpoint.
  const path = isBoardTarget(target)
    ? `/api/boards/${encodeURIComponent(target.slice(1))}/messages`
    : `/api/dms/${encodeURIComponent(target.slice(1))}`;

  const response = await fetch(`${account.host}${path}`, {
    method: "POST",
    headers: {
      "Content-Type": "application/json",
      Authorization: `Bearer ${account.apiKey}`,
      "X-PulseBoard-Username": account.username,
    },
    body: JSON.stringify({ text }),
  });

  if (!response.ok) {
    throw new Error(
      `PulseBoard send failed: HTTP ${response.status} ${response.statusText} (target: ${target})`,
    );
  }

  const data = (await response.json()) as { id?: string };
  const messageId = data.id ?? `pb-${Date.now()}`;

  recordOutboundActivity(account.accountId);

  return { messageId, target };
}

