import type { ResolvedPulseBoardAccount } from "./accounts.js";
import type { CoreConfig, PulseBoardInboundMessage, PluginRuntime } from "./types.js";

export interface PulseBoardMonitorOptions {
  accountId: string;
  account: ResolvedPulseBoardAccount;
  cfg: CoreConfig;
  runtime: PluginRuntime;
  abortSignal: AbortSignal;
  onMessage: (msg: PulseBoardInboundMessage) => Promise<void>;
  onError: (err: Error, context: string) => void;
  setStatus: (status: Partial<{ connected: boolean; running: boolean }>) => void;
}

/** How often to poll for new messages when there is no server-push mechanism. */
const POLL_INTERVAL_MS = 5_000;

/** Parse a raw board-message object from the PulseBoard REST API. */
function parseBoardMessage(raw: unknown, boardName: string): PulseBoardInboundMessage | null {
  if (!raw || typeof raw !== "object") {
    return null;
  }
  const r = raw as Record<string, unknown>;
  const id = typeof r["id"] === "string" ? r["id"] : null;
  const sender = typeof r["sender"] === "string" ? r["sender"] : null;
  const text = typeof r["text"] === "string" ? r["text"] : null;
  const ts = typeof r["timestamp"] === "number" ? r["timestamp"] : Date.now();
  if (!id || !sender || !text) {
    return null;
  }
  return {
    messageId: id,
    target: `#${boardName}`,
    senderUsername: sender,
    text,
    timestamp: ts,
    isGroup: true,
  };
}

/** Parse a raw DM object from the PulseBoard REST API. */
function parseDirectMessage(raw: unknown): PulseBoardInboundMessage | null {
  if (!raw || typeof raw !== "object") {
    return null;
  }
  const r = raw as Record<string, unknown>;
  const id = typeof r["id"] === "string" ? r["id"] : null;
  const sender = typeof r["sender"] === "string" ? r["sender"] : null;
  const text = typeof r["text"] === "string" ? r["text"] : null;
  const ts = typeof r["timestamp"] === "number" ? r["timestamp"] : Date.now();
  if (!id || !sender || !text) {
    return null;
  }
  return {
    messageId: id,
    target: `@${sender}`,
    senderUsername: sender,
    text,
    timestamp: ts,
    isGroup: false,
  };
}

/**
 * Fetch all new messages (board posts + DMs) from the PulseBoard server
 * since the given cursor (most recent seen message ID).
 */
async function fetchNewMessages(
  account: ResolvedPulseBoardAccount,
  since: string | null,
): Promise<PulseBoardInboundMessage[]> {
  const headers: Record<string, string> = {
    Authorization: `Bearer ${account.apiKey}`,
    "X-PulseBoard-Username": account.username,
    Accept: "application/json",
  };

  const sinceParam = since ? `?since=${encodeURIComponent(since)}` : "";
  const messages: PulseBoardInboundMessage[] = [];

  // Poll each subscribed board for new posts.
  for (const board of account.boards) {
    const url = `${account.host}/api/boards/${encodeURIComponent(board)}/messages${sinceParam}`;
    try {
      const res = await fetch(url, { headers });
      if (!res.ok) {
        continue;
      }
      const data = (await res.json()) as { messages?: unknown[] };
      for (const raw of data.messages ?? []) {
        const msg = parseBoardMessage(raw, board);
        if (msg) {
          messages.push(msg);
        }
      }
    } catch {
      // Individual board poll failures are non-fatal; continue to next board.
    }
  }

  // Poll the DM inbox.
  try {
    const dmUrl = `${account.host}/api/dms/inbox${sinceParam}`;
    const dmRes = await fetch(dmUrl, { headers });
    if (dmRes.ok) {
      const data = (await dmRes.json()) as { messages?: unknown[] };
      for (const raw of data.messages ?? []) {
        const msg = parseDirectMessage(raw);
        if (msg) {
          messages.push(msg);
        }
      }
    }
  } catch {
    // DM poll failures are non-fatal.
  }

  // Sort by timestamp ascending so messages are dispatched in order.
  messages.sort((a, b) => a.timestamp - b.timestamp);
  return messages;
}

/**
 * Sleep for the given duration or until the abort signal fires.
 * Resolves immediately if the signal is already aborted.
 */
function sleepOrAbort(ms: number, signal: AbortSignal): Promise<void> {
  return new Promise<void>((resolve) => {
    if (signal.aborted) {
      resolve();
      return;
    }
    const timer = setTimeout(resolve, ms);
    signal.addEventListener("abort", () => {
      clearTimeout(timer);
      resolve();
    }, { once: true });
  });
}

/**
 * Poll the PulseBoard server for new messages in a loop until the abort
 * signal fires.  Calls `onMessage` for each message received and `onError`
 * for non-fatal poll errors.
 */
export async function monitorPulseBoardAccount(opts: PulseBoardMonitorOptions): Promise<void> {
  const { account, abortSignal, onMessage, onError, setStatus } = opts;

  // Cursor: ID of the last message we have seen (null = start from now).
  let cursor: string | null = null;

  setStatus({ connected: true, running: true });

  while (!abortSignal.aborted) {
    try {
      const messages = await fetchNewMessages(account, cursor);
      for (const msg of messages) {
        // Advance cursor so we never re-deliver the same message.
        cursor = msg.messageId;
        try {
          await onMessage(msg);
        } catch (err) {
          onError(err instanceof Error ? err : new Error(String(err)), "dispatch");
        }
      }
      // Restore connected status after a successful poll cycle.
      setStatus({ connected: true });
    } catch (err) {
      onError(err instanceof Error ? err : new Error(String(err)), "poll");
      setStatus({ connected: false });
    }

    await sleepOrAbort(POLL_INTERVAL_MS, abortSignal);
  }

  setStatus({ connected: false, running: false });
}

