import type { ChannelSetupAdapter } from "openclaw/plugin-sdk/channel-setup";
import { DEFAULT_ACCOUNT_ID } from "openclaw/plugin-sdk/account-id";
import type { OpenClawConfig } from "openclaw/plugin-sdk/config-runtime";
import {
  createStandardChannelSetupStatus,
  createTopLevelChannelDmPolicy,
  createTopLevelChannelParsedAllowFromPrompt,
  formatDocsLink,
  mergeAllowFromEntries,
  parseSetupEntriesWithParser,
  patchTopLevelChannelConfigSection,
  splitSetupEntries,
} from "openclaw/plugin-sdk/setup";
import type { ChannelSetupWizard } from "openclaw/plugin-sdk/setup";
import { resolvePulseBoardAccount } from "./accounts.js";
import { normalizeBoardName, normalizePulseBoardAllowEntry } from "./normalize.js";
import type { CoreConfig } from "./types.js";

const channel = "pulseboard" as const;

const PULSEBOARD_SETUP_HELP = [
  "Configure your PulseBoard connection.",
  "You will need a PulseBoard server URL, an API key, and a username.",
  "Env vars (default account): PULSEBOARD_HOST, PULSEBOARD_API_KEY, PULSEBOARD_USERNAME.",
  `Docs: ${formatDocsLink("/channels/pulseboard", "channels/pulseboard")}`,
];

const PULSEBOARD_ALLOW_FROM_HELP = [
  "Restrict DMs to specific PulseBoard usernames.",
  "Examples: alice, bob, alice,bob",
  'Use "*" to allow all senders.',
  `Docs: ${formatDocsLink("/channels/pulseboard", "channels/pulseboard")}`,
];

/** Parse a comma-separated list of board names entered during setup. */
function parseBoardNamesInput(raw: string): { boards: string[]; error?: string } {
  const entries = splitSetupEntries(raw);
  const boards: string[] = [];
  for (const entry of entries) {
    const normalized = normalizeBoardName(entry);
    if (!normalized) {
      return {
        boards: [],
        error: `Invalid board name: "${entry}". Use letters, digits, hyphens, and underscores only.`,
      };
    }
    boards.push(normalized);
  }
  return { boards: [...new Set(boards)] };
}

/** Parse a comma-separated allow-list entered during setup. */
function parsePulseBoardAllowFrom(raw: string): { entries: string[]; error?: string } {
  return parseSetupEntriesWithParser(raw, (entry) => {
    if (entry.trim() === "*") {
      return { value: "*" };
    }
    const normalized = normalizePulseBoardAllowEntry(entry);
    if (!normalized) {
      return { error: `Invalid username: "${entry}". Use letters, digits, hyphens, and underscores.` };
    }
    return { value: normalized };
  });
}

/** Programmatic setup adapter used by `openclaw channels configure pulseboard`. */
export const pulseBoardSetupAdapter: ChannelSetupAdapter = {
