      },
    },
    status: createComputedAccountStatusAdapter<ResolvedPulseBoardAccount>({
      defaultRuntime: createDefaultChannelRuntimeState(DEFAULT_ACCOUNT_ID),
      buildChannelSummary: ({ snapshot }) =>
        buildPassiveChannelStatusSummary(snapshot, {
          host: (snapshot as Record<string, unknown>)["host"] as string | null ?? null,
          username: (snapshot as Record<string, unknown>)["username"] as string | null ?? null,
        }),
      resolveAccountSnapshot: ({ account, runtime }) => ({
        accountId: account.accountId,
        name: account.name,
        enabled: account.enabled,
        configured: account.configured,
        extra: {
          host: account.host,
          username: account.username,
          boards: account.boards,
          ...buildTrafficStatusSummary(runtime),
        },
      }),
    }),
    gateway: {
      startAccount: async (ctx) => {
        const account = ctx.account;

        if (!account.configured) {
          throw new Error(
            `PulseBoard is not configured for account "${account.accountId}". ` +
              "Set channels.pulseboard.host, channels.pulseboard.apiKey, and channels.pulseboard.username.",
          );
        }

        ctx.log?.info(
          `[${account.accountId}] starting PulseBoard provider ` +
            `(host: ${account.host}, user: ${account.username}, ` +
            `boards: ${account.boards.length > 0 ? account.boards.join(", ") : "(none)"})`,
        );

        const runtime = getPulseBoardRuntime();
        const pairing = createChannelPairingController({
          core: runtime,
          channel: "pulseboard",
          accountId: account.accountId,
        });

        await runStoppablePassiveMonitor({
          abortSignal: ctx.abortSignal,
          start: async () => {
            await monitorPulseBoardAccount({
              accountId: account.accountId,
              account,
              cfg: ctx.cfg as CoreConfig,
              runtime,
              abortSignal: ctx.abortSignal,
              setStatus: ctx.setStatus,
              onError: (err, context) => {
                ctx.log?.error?.(
                  `[${account.accountId}] PulseBoard error (${context}): ${err.message}`,
                );
              },
              onMessage: async (msg) => {
                // Resolve DM access for this sender.  Group (board) messages bypass
                // the DM policy but still go through command authorization.
                const access = await resolveInboundDirectDmAccessWithRuntime({
                  cfg: ctx.cfg,
                  channel: "pulseboard",
                  accountId: account.accountId,
                  dmPolicy: msg.isGroup ? "open" : (account.config.dmPolicy ?? "pairing"),
                  allowFrom: account.config.allowFrom,
                  senderId: msg.senderUsername,
                  rawBody: msg.text,
                  isSenderAllowed: (sender, allowFrom) =>
                    isPulseBoardSenderAllowed(sender, allowFrom as Array<string | number>),
                  runtime: {
                    shouldComputeCommandAuthorized:
                      runtime.channel.commands.shouldComputeCommandAuthorized,
                    resolveCommandAuthorizedFromAuthorizers:
                      runtime.channel.commands.resolveCommandAuthorizedFromAuthorizers,
                  },
                  modeWhenAccessGroupsOff: "configured",
                });

                // For DMs that require pairing, issue a challenge and bail.
                if (!msg.isGroup && access.access.decision === "challenge") {
                  await pairing.issueChallenge({
                    senderId: msg.senderUsername,
                    senderIdLine: `Your PulseBoard username: ${msg.senderUsername}`,
                    sendPairingReply: async (text) => {
                      await sendMessagePulseBoard(`@${msg.senderUsername}`, text, {
                        cfg: ctx.cfg as CoreConfig,
                        accountId: account.accountId,
                      });
                    },
                    onCreated: () => {
                      ctx.log?.debug?.(
                        `[${account.accountId}] PulseBoard pairing request from ${msg.senderUsername}`,
                      );
                    },
                    onReplyError: (err) => {
                      ctx.log?.warn?.(
                        `[${account.accountId}] PulseBoard pairing reply failed for ` +
                          `${msg.senderUsername}: ${String(err)}`,
                      );
                    },
                  });
                  return;
                }

                if (access.access.decision !== "allow") {
                  ctx.log?.debug?.(
                    `[${account.accountId}] dropping PulseBoard message from ` +
                      `${msg.senderUsername} (${access.access.reason})`,
                  );
                  return;
                }

                // Dispatch the message to the OpenClaw agent runtime.
                await dispatchInboundDirectDmWithRuntime({
                  cfg: ctx.cfg,
                  runtime,
                  channel: "pulseboard",
                  channelLabel: "PulseBoard",
                  accountId: account.accountId,
                  peer: msg.isGroup
                    ? { kind: "group", groupId: msg.target }
                    : { kind: "direct", id: msg.senderUsername },
                  senderId: msg.senderUsername,
                  senderAddress: `pulseboard:@${msg.senderUsername}`,
                  recipientAddress: msg.isGroup
                    ? `pulseboard:${msg.target}`
                    : `pulseboard:@${account.username}`,
                  conversationLabel: msg.isGroup ? msg.target : msg.senderUsername,
                  rawBody: msg.text,
                  messageId: msg.messageId,
                  timestamp: msg.timestamp,
                  commandAuthorized: access.commandAuthorized,
                  deliver: async (payload) => {
                    const outboundText =
                      payload && typeof payload === "object" && "text" in payload
                        ? String((payload as { text?: string }).text ?? "")
                        : "";
                    if (!outboundText.trim()) {
                      return;
                    }
                    // Reply to the board or back to the DM sender.
                    const replyTarget = msg.isGroup ? msg.target : `@${msg.senderUsername}`;
                    await sendMessagePulseBoard(replyTarget, outboundText, {
                      cfg: ctx.cfg as CoreConfig,
                      accountId: account.accountId,
                    });
                  },
                  onRecordError: (err) => {
                    ctx.log?.error?.(
                      `[${account.accountId}] failed recording PulseBoard inbound session: ${String(err)}`,
                    );
                  },
                  onDispatchError: (err, info) => {
                    ctx.log?.error?.(
                      `[${account.accountId}] PulseBoard ${info.kind} reply failed: ${String(err)}`,
                    );
                  },
                });
              },
            });
          },
        });
      },
    },
  },

  // ---------------------------------------------------------------------------
  // Pairing
  // ---------------------------------------------------------------------------

  pairing: {
    text: {
      idLabel: "pulseBoardUsername",
      message: "Your pairing request has been approved!",
      normalizeAllowEntry: (entry) => normalizePulseBoardAllowEntry(entry) ?? entry,
      notify: async ({ id, message }) => {
        // Send approval notification as a DM to the pairing requester.
        await sendMessagePulseBoard(`@${id}`, message);
      },
    },
  },

  // ---------------------------------------------------------------------------
  // Security
  // ---------------------------------------------------------------------------

  security: {
    resolveDmPolicy: resolvePulseBoardDmPolicy,
  },

  // ---------------------------------------------------------------------------
  // Outbound
  // ---------------------------------------------------------------------------

  outbound: {
    deliveryMode: "direct",
    // PulseBoard supports up to 4000 characters per message.
    textChunkLimit: 4000,
    sendText: async ({ cfg, to, text, accountId }) => {
      const result = await sendMessagePulseBoard(to, text, {
        cfg: cfg as CoreConfig,
        accountId: accountId ?? undefined,
      });
      return attachChannelToResult("pulseboard", {
        to: result.target,
        messageId: result.messageId,
      });
    },
  },
});

