import { describe, expect, it } from "vitest";
import {
  isBoardTarget,
  isDmTarget,
  isPulseBoardSenderAllowed,
  looksLikePulseBoardTargetId,
  normalizeBoardName,
  normalizePulseBoardAllowEntry,
  normalizePulseBoardTarget,
  normalizeUsername,
} from "./normalize.js";

// ---------------------------------------------------------------------------
// normalizeBoardName
// ---------------------------------------------------------------------------

describe("normalizeBoardName", () => {
  it("strips leading # and lowercases", () => {
    expect(normalizeBoardName("#General")).toBe("general");
    expect(normalizeBoardName("##Tech")).toBe("tech");
    expect(normalizeBoardName("announcements")).toBe("announcements");
    expect(normalizeBoardName("my-board_01")).toBe("my-board_01");
  });

  it("returns null for names with spaces or invalid characters", () => {
    expect(normalizeBoardName("#bad board")).toBeNull();
    expect(normalizeBoardName("#board!")).toBeNull();
    expect(normalizeBoardName("#board.name")).toBeNull();
  });

  it("returns null for empty input", () => {
    expect(normalizeBoardName("")).toBeNull();
    expect(normalizeBoardName("  ")).toBeNull();
    expect(normalizeBoardName("#")).toBeNull();
  });

  it("returns null for names exceeding 64 characters", () => {
    expect(normalizeBoardName("a".repeat(65))).toBeNull();
    expect(normalizeBoardName("#" + "a".repeat(65))).toBeNull();
  });

  it("accepts names exactly 64 characters long", () => {
    expect(normalizeBoardName("a".repeat(64))).toBe("a".repeat(64));
  });
});

// ---------------------------------------------------------------------------
// normalizeUsername
// ---------------------------------------------------------------------------

describe("normalizeUsername", () => {
  it("strips leading @ and lowercases", () => {
    expect(normalizeUsername("@Alice")).toBe("alice");
    expect(normalizeUsername("@@@Bob")).toBe("bob");
    expect(normalizeUsername("carol")).toBe("carol");
    expect(normalizeUsername("user.name+tag")).toBe("user.name+tag");
  });

  it("returns null for names with spaces or invalid characters", () => {
    expect(normalizeUsername("bad user")).toBeNull();
    expect(normalizeUsername("user@host")).toBeNull();
    expect(normalizeUsername("user#tag")).toBeNull();
  });

  it("returns null for empty input", () => {
    expect(normalizeUsername("")).toBeNull();
    expect(normalizeUsername("  ")).toBeNull();
    expect(normalizeUsername("@")).toBeNull();
  });
});

// ---------------------------------------------------------------------------
// normalizePulseBoardTarget
// ---------------------------------------------------------------------------

describe("normalizePulseBoardTarget", () => {
  it("normalizes board targets", () => {
    expect(normalizePulseBoardTarget("#general")).toBe("#general");
    expect(normalizePulseBoardTarget("#General")).toBe("#general");
    expect(normalizePulseBoardTarget("##announcements")).toBe("#announcements");
    expect(normalizePulseBoardTarget("pulseboard:#tech")).toBe("#tech");
    expect(normalizePulseBoardTarget("PULSEBOARD:#Tech")).toBe("#tech");
  });

  it("normalizes DM targets", () => {
    expect(normalizePulseBoardTarget("@alice")).toBe("@alice");
    expect(normalizePulseBoardTarget("@Alice")).toBe("@alice");
    expect(normalizePulseBoardTarget("@@bob")).toBe("@bob");
    expect(normalizePulseBoardTarget("pulseboard:@carol")).toBe("@carol");
  });

  it("treats bare words as board names", () => {
    expect(normalizePulseBoardTarget("general")).toBe("#general");
    expect(normalizePulseBoardTarget("my-board")).toBe("#my-board");
  });

  it("returns null for empty or invalid input", () => {
    expect(normalizePulseBoardTarget("")).toBeNull();
    expect(normalizePulseBoardTarget("  ")).toBeNull();
    expect(normalizePulseBoardTarget("@bad user")).toBeNull();
    expect(normalizePulseBoardTarget("#bad board")).toBeNull();
    expect(normalizePulseBoardTarget("bad!target")).toBeNull();
  });
});

// ---------------------------------------------------------------------------
// isBoardTarget / isDmTarget
// ---------------------------------------------------------------------------

describe("isBoardTarget", () => {
  it("returns true for #-prefixed targets", () => {
    expect(isBoardTarget("#general")).toBe(true);
    expect(isBoardTarget("#tech")).toBe(true);
  });

  it("returns false for @-prefixed targets", () => {
    expect(isBoardTarget("@alice")).toBe(false);
  });
});

describe("isDmTarget", () => {
  it("returns true for @-prefixed targets", () => {
    expect(isDmTarget("@alice")).toBe(true);
  });

  it("returns false for #-prefixed targets", () => {
    expect(isDmTarget("#general")).toBe(false);
  });
});

// ---------------------------------------------------------------------------
// looksLikePulseBoardTargetId
// ---------------------------------------------------------------------------

describe("looksLikePulseBoardTargetId", () => {
  it("recognizes board and DM targets", () => {
    expect(looksLikePulseBoardTargetId("#general")).toBe(true);
    expect(looksLikePulseBoardTargetId("@alice")).toBe(true);
    expect(looksLikePulseBoardTargetId("pulseboard:#tech")).toBe(true);
    expect(looksLikePulseBoardTargetId("pulseboard:@bob")).toBe(true);
    expect(looksLikePulseBoardTargetId("PULSEBOARD:@carol")).toBe(true);
  });

  it("rejects bare words, empty strings, and other formats", () => {
    expect(looksLikePulseBoardTargetId("")).toBe(false);
    expect(looksLikePulseBoardTargetId("just-text")).toBe(false);
    expect(looksLikePulseBoardTargetId("nostr:npub1abc")).toBe(false);
  });
});

// ---------------------------------------------------------------------------
// normalizePulseBoardAllowEntry
// ---------------------------------------------------------------------------

describe("normalizePulseBoardAllowEntry", () => {
  it("normalizes bare usernames", () => {
    expect(normalizePulseBoardAllowEntry("Alice")).toBe("alice");
    expect(normalizePulseBoardAllowEntry("  Bob  ")).toBe("bob");
  });

  it("strips a leading @ prefix", () => {
    expect(normalizePulseBoardAllowEntry("@carol")).toBe("carol");
  });

  it("passes through the wildcard", () => {
    expect(normalizePulseBoardAllowEntry("*")).toBe("*");
    expect(normalizePulseBoardAllowEntry("  *  ")).toBe("*");
  });

  it("returns null for invalid or empty entries", () => {
    expect(normalizePulseBoardAllowEntry("")).toBeNull();
    expect(normalizePulseBoardAllowEntry("bad user")).toBeNull();
    expect(normalizePulseBoardAllowEntry("user@host")).toBeNull();
  });
});

// ---------------------------------------------------------------------------
// isPulseBoardSenderAllowed
// ---------------------------------------------------------------------------

describe("isPulseBoardSenderAllowed", () => {
  it("allows a sender present in the list", () => {
    expect(isPulseBoardSenderAllowed("alice", ["alice", "bob"])).toBe(true);
    expect(isPulseBoardSenderAllowed("Bob", ["alice", "bob"])).toBe(true);
  });

  it("allows any sender when the wildcard is present", () => {
    expect(isPulseBoardSenderAllowed("anyone", ["*"])).toBe(true);
    expect(isPulseBoardSenderAllowed("anyone", ["alice", "*"])).toBe(true);
  });

  it("rejects a sender not in the list", () => {
    expect(isPulseBoardSenderAllowed("eve", ["alice", "bob"])).toBe(false);
  });

  it("rejects an empty or invalid sender username", () => {
    expect(isPulseBoardSenderAllowed("", ["*"])).toBe(false);
    expect(isPulseBoardSenderAllowed("bad user", ["*"])).toBe(false);
  });
});

